    private Patient editingPatient = new();

    protected override async Task OnInitializedAsync()
    {
        patients = await Clinic.GetPatientsAsync();
        owners = await Clinic.GetOwnersAsync();
    }

    private async Task SearchAsync()
    {
        patients = await Clinic.GetPatientsAsync(searchTerm);
    }

    private void ShowRegisterForm()
    {
        editingPatient = new Patient { DateOfBirth = DateTime.Today.AddYears(-1) };
        showForm = true;
    }

    private void EditPatient(Patient p)
    {
        editingPatient = p;
        showForm = true;
    }

    private async Task SavePatient()
    {
        await Clinic.SavePatientAsync(editingPatient);
        showForm = false;
        patients = await Clinic.GetPatientsAsync(searchTerm);
    }

    private void CancelForm() => showForm = false;

    private string GetAge(DateTime dob)
    {
        var age = DateTime.Today.Year - dob.Year;
        if (dob.Date > DateTime.Today.AddYears(-age)) age--;
        return age < 1 ? "< 1 yr" : $"{age} yr";
    }
}
