    {
        allPatients = await Clinic.GetPatientsAsync();
        await LoadAppointments();
    }

    private async Task LoadAppointments()
    {
        appointments = await Clinic.GetAllAppointmentsAsync(weekStart, weekStart.AddDays(7));
    }

    private void PrevWeek() { weekStart = weekStart.AddDays(-7); _ = LoadAppointments(); }
    private void NextWeek() { weekStart = weekStart.AddDays(7); _ = LoadAppointments(); }
    private void GoToToday() { weekStart = DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek); _ = LoadAppointments(); }

