@code {
    private int todayAppointments, totalPatients, pendingInvoices;
    private decimal weekRevenue;
    private List<Appointment> todaySchedule = new();

    protected override async Task OnInitializedAsync()
    {
        var today = DateTime.Today;
        var weekStart = today.AddDays(-(int)today.DayOfWeek);
        todaySchedule = await Clinic.GetAppointmentsAsync(today, today.AddDays(1));
        todayAppointments = todaySchedule.Count;
        totalPatients = (await Clinic.GetPatientsAsync()).Count;
        var invoices = await Clinic.GetInvoicesAsync();
        pendingInvoices = invoices.Count(i => i.Status == InvoiceStatus.Pending || i.Status == InvoiceStatus.PartiallyPaid);
        weekRevenue = (await Clinic.GetPaymentsAsync())
            .Where(p => p.PaymentDate >= weekStart)
            .Sum(p => p.Amount);
    }

    private async Task UpdateStatus(Appointment apt, ChangeEventArgs e)
    {
        if (Enum.TryParse<AppointmentStatus>(e.Value?.ToString(), out var status))
        {
            apt.Status = status;
            await Clinic.SaveAppointmentAsync(apt);
        }
    }
}
