using Microsoft.EntityFrameworkCore;

namespace VetClinic.Data;

public class ClinicService(ApplicationDbContext db)
{
    // --- Owners ---
    public async Task<List<Owner>> GetOwnersAsync(string? search = null)
    {
        var query = db.Owners.Include(o => o.Patients).AsQueryable();
        if (!string.IsNullOrWhiteSpace(search))
            query = query.Where(o => o.LastName.Contains(search) || o.FirstName.Contains(search) || o.Phone.Contains(search));
        return await query.OrderBy(o => o.LastName).ToListAsync();
    }

    public async Task<Owner?> GetOwnerAsync(int id) =>
        await db.Owners.Include(o => o.Patients).FirstOrDefaultAsync(o => o.Id == id);

    public async Task SaveOwnerAsync(Owner owner)
    {
        if (owner.Id == 0) db.Owners.Add(owner);
        else db.Owners.Update(owner);
        await db.SaveChangesAsync();
    }

    // --- Patients ---
    public async Task<List<Patient>> GetPatientsAsync(string? search = null)
    {
        var query = db.Patients.Include(p => p.Owner).AsQueryable();
        if (!string.IsNullOrWhiteSpace(search))
            query = query.Where(p => p.Name.Contains(search) || p.Owner.LastName.Contains(search));
        return await query.OrderBy(p => p.Name).ToListAsync();
    }

    public async Task<Patient?> GetPatientAsync(int id) =>
        await db.Patients.Include(p => p.Owner).Include(p => p.TreatmentNotes.OrderByDescending(t => t.Date))
            .Include(p => p.Appointments.OrderByDescending(a => a.StartTime))
            .FirstOrDefaultAsync(p => p.Id == id);

    public async Task SavePatientAsync(Patient patient)
    {
        if (patient.Id == 0) db.Patients.Add(patient);
        else db.Patients.Update(patient);
        await db.SaveChangesAsync();
    }

    // --- Treatment Notes ---
    public async Task SaveTreatmentNoteAsync(TreatmentNote note)
    {
        if (note.Id == 0) db.TreatmentNotes.Add(note);
        else db.TreatmentNotes.Update(note);
        await db.SaveChangesAsync();
    }

    // --- Appointments ---
    public async Task<List<Appointment>> GetAppointmentsAsync(DateTime from, DateTime to) =>
        await db.Appointments.Include(a => a.Patient).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= from && a.StartTime <= to && a.Status != AppointmentStatus.Cancelled)
            .OrderBy(a => a.StartTime).ToListAsync();

    public async Task<List<Appointment>> GetAllAppointmentsAsync(DateTime from, DateTime to) =>
        await db.Appointments.Include(a => a.Patient).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= from && a.StartTime <= to)
            .OrderBy(a => a.StartTime).ToListAsync();

    public async Task<Appointment?> GetAppointmentAsync(int id) =>
        await db.Appointments.Include(a => a.Patient).ThenInclude(p => p.Owner)
            .FirstOrDefaultAsync(a => a.Id == id);

    public async Task SaveAppointmentAsync(Appointment appointment)
    {
        if (appointment.Id == 0) db.Appointments.Add(appointment);
        else db.Appointments.Update(appointment);
        await db.SaveChangesAsync();
    }

    public bool HasConflict(DateTime start, DateTime end, int? excludeId = null)
    {
        return db.Appointments.Any(a =>
            a.Id != (excludeId ?? 0) &&
            a.Status == AppointmentStatus.Scheduled &&
            a.StartTime < end && a.EndTime > start);
    }

    // --- Invoices ---
    public async Task<List<Invoice>> GetInvoicesAsync(string? search = null)
    {
        var query = db.Invoices.Include(i => i.Patient).ThenInclude(p => p.Owner)
            .Include(i => i.LineItems).Include(i => i.Payments).AsQueryable();
        if (!string.IsNullOrWhiteSpace(search))
            query = query.Where(i => i.Patient.Name.Contains(search) || i.Patient.Owner.LastName.Contains(search));
        return await query.OrderByDescending(i => i.IssuedDate).ToListAsync();
    }

    public async Task<Invoice?> GetInvoiceAsync(int id) =>
        await db.Invoices.Include(i => i.Patient).ThenInclude(p => p.Owner)
            .Include(i => i.LineItems).Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == id);

    public async Task SaveInvoiceAsync(Invoice invoice)
    {
        if (invoice.Id == 0) db.Invoices.Add(invoice);
        else db.Invoices.Update(invoice);
        await db.SaveChangesAsync();
    }

    public async Task AddLineItemAsync(InvoiceLineItem item)
    {
        db.InvoiceLineItems.Add(item);
        await db.SaveChangesAsync();
    }

    public async Task RemoveLineItemAsync(int id)
    {
        var item = await db.InvoiceLineItems.FindAsync(id);
        if (item != null)
        {
            db.InvoiceLineItems.Remove(item);
            await db.SaveChangesAsync();
        }
    }

    // --- Payments ---
    public async Task<List<Payment>> GetPaymentsAsync() =>
        await db.Payments.Include(p => p.Invoice).ThenInclude(i => i.Patient)
            .OrderByDescending(p => p.PaymentDate).ToListAsync();

    public async Task SavePaymentAsync(Payment payment)
    {
        db.Payments.Add(payment);
        // Update invoice status
        var invoice = await db.Invoices.Include(i => i.Payments).FirstOrDefaultAsync(i => i.Id == payment.InvoiceId);
        if (invoice != null)
        {
            var totalPaid = invoice.Payments.Sum(p => p.Amount) + payment.Amount;
            invoice.Status = totalPaid >= invoice.TotalAmount ? InvoiceStatus.Paid : InvoiceStatus.PartiallyPaid;
        }
        await db.SaveChangesAsync();
    }
}

