@page "/"
@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data
@attribute [Authorize]
@inject ClinicService Clinic

<PageTitle>VetClinic - Dashboard</PageTitle>

<h1>Dashboard</h1>

<div class="row mb-4">
    <div class="col-md-3">
        <div class="card text-bg-primary">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-6">@todayAppointments</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-success">
            <div class="card-body">
                <h5 class="card-title">Total Patients</h5>
                <p class="card-text display-6">@totalPatients</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-warning">
            <div class="card-body">
                <h5 class="card-title">Pending Invoices</h5>
                <p class="card-text display-6">@pendingInvoices</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-info">
            <div class="card-body">
                <h5 class="card-title">This Week Revenue</h5>
                <p class="card-text display-6">$@weekRevenue.ToString("N0")</p>
            </div>
        </div>
    </div>
</div>

<h4>Today's Schedule</h4>
@if (todaySchedule.Any())
{
    <table class="table table-striped">
        <thead>
            <tr><th>Time</th><th>Patient</th><th>Owner</th><th>Reason</th><th>Vet</th><th>Status</th></tr>
        </thead>
        <tbody>
            @foreach (var apt in todaySchedule)
            {
                <tr>
                    <td>@apt.StartTime.ToString("h:mm tt") - @apt.EndTime.ToString("h:mm tt")</td>
                    <td>@apt.Patient.Name</td>
                    <td>@apt.Patient.Owner.LastName</td>
                    <td>@apt.Reason</td>
                    <td>@apt.VeterinarianName</td>
                    <td>
                        <select class="form-select form-select-sm" value="@apt.Status"
                            @onchange="e => UpdateStatus(apt, e)">
                            @foreach (var s in Enum.GetValues<AppointmentStatus>())
                            {
                                <option value="@s" selected="@(apt.Status == s)">@s</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}
else
{
    <p class="text-muted">No appointments scheduled for today.</p>
}

@code {
    private int todayAppointments, totalPatients, pendingInvoices;
    private decimal weekRevenue;
    private List<Appointment> todaySchedule = new();

    protected override async Task OnInitializedAsync()
    {
        var today = DateTime.Today;
        var weekStart = today.AddDays(-(int)today.DayOfWeek);
        todaySchedule = await Clinic.GetAppointmentsAsync(today, today.AddDays(1));
        todayAppointments = todaySchedule.Count;
        totalPatients = (await Clinic.GetPatientsAsync()).Count;
        var invoices = await Clinic.GetInvoicesAsync();
        pendingInvoices = invoices.Count(i => i.Status == InvoiceStatus.Pending || i.Status == InvoiceStatus.PartiallyPaid);
        weekRevenue = (await Clinic.GetPaymentsAsync())
            .Where(p => p.PaymentDate >= weekStart)
            .Sum(p => p.Amount);
    }

    private async Task UpdateStatus(Appointment apt, ChangeEventArgs e)
    {
        if (Enum.TryParse<AppointmentStatus>(e.Value?.ToString(), out var status))
        {
            apt.Status = status;
            await Clinic.SaveAppointmentAsync(apt);
        }
    }
}

