@page "/patients"
@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data
@attribute [Authorize]
@inject ClinicService Clinic

<PageTitle>Patients</PageTitle>

<h1>Patients</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by name or owner..."
            @bind="searchTerm" @bind:event="oninput" @bind:after="SearchAsync" />
    </div>
    <div class="col-md-6 text-end">
        <button class="btn btn-primary" @onclick="ShowRegisterForm">+ Register New Patient</button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-4">
        <div class="card-header">@(editingPatient.Id == 0 ? "Register New Patient" : "Edit Patient")</div>
        <div class="card-body">
            <EditForm Model="editingPatient" OnValidSubmit="SavePatient" FormName="patientForm">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-6 mb-3">
                        <label class="form-label">Pet Name</label>
                        <InputText class="form-control" @bind-Value="editingPatient.Name" />
                    </div>
                    <div class="col-md-3 mb-3">
                        <label class="form-label">Species</label>
                        <InputSelect class="form-control" @bind-Value="editingPatient.Species">
                            <option value="">Select...</option>
                            <option value="Dog">Dog</option>
                            <option value="Cat">Cat</option>
                            <option value="Bird">Bird</option>
                            <option value="Rabbit">Rabbit</option>
                            <option value="Reptile">Reptile</option>
                            <option value="Other">Other</option>
                        </InputSelect>
                    </div>
                    <div class="col-md-3 mb-3">
                        <label class="form-label">Breed</label>
                        <InputText class="form-control" @bind-Value="editingPatient.Breed" />
                    </div>
                </div>
                <div class="row">
                    <div class="col-md-3 mb-3">
                        <label class="form-label">Date of Birth</label>
                        <InputDate class="form-control" @bind-Value="editingPatient.DateOfBirth" />
                    </div>
                    <div class="col-md-3 mb-3">
                        <label class="form-label">Weight (kg)</label>
                        <InputNumber class="form-control" @bind-Value="editingPatient.Weight" />
                    </div>
