@page "/appointments"
@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data
@attribute [Authorize]
@inject ClinicService Clinic

<PageTitle>Appointments</PageTitle>

<h1>Appointment Schedule</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <div class="input-group">
            <button class="btn btn-outline-secondary" @onclick="PrevWeek">&lt;</button>
            <input type="date" class="form-control" @bind="weekStart" @bind:after="LoadAppointments" />
            <button class="btn btn-outline-secondary" @onclick="NextWeek">&gt;</button>
            <button class="btn btn-outline-primary" @onclick="GoToToday">Today</button>
        </div>
    </div>
    <div class="col-md-8 text-end">
        <button class="btn btn-primary" @onclick="ShowNewForm">+ New Appointment</button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-4">
        <div class="card-header">@(editingApt.Id == 0 ? "Schedule Appointment" : "Edit Appointment")</div>
        <div class="card-body">
            @if (!string.IsNullOrEmpty(conflictMessage))
            {
                <div class="alert alert-danger">@conflictMessage</div>
            }
            <EditForm Model="editingApt" OnValidSubmit="SaveAppointment" FormName="aptForm">
                <div class="row">
                    <div class="col-md-4 mb-3">
                        <label class="form-label">Patient</label>
                        <InputSelect class="form-control" @bind-Value="editingApt.PatientId">
                            <option value="0">Select patient...</option>
                            @foreach (var p in allPatients)
                            {
                                <option value="@p.Id">@p.Name (@p.Owner.LastName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-4 mb-3">
                        <label class="form-label">Start Time</label>
                        <InputDate Type="InputDateType.DateTimeLocal" class="form-control" @bind-Value="editingApt.StartTime" />
                    </div>
                    <div class="col-md-4 mb-3">
                        <label class="form-label">End Time</label>
                        <InputDate Type="InputDateType.DateTimeLocal" class="form-control" @bind-Value="editingApt.EndTime" />
                    </div>
                </div>
                <div class="row">
                    <div class="col-md-4 mb-3">
                        <label class="form-label">Veterinarian</label>
                        <InputText class="form-control" @bind-Value="editingApt.VeterinarianName" />
                    </div>
                    <div class="col-md-4 mb-3">
                        <label class="form-label">Reason</label>
                        <InputText class="form-control" @bind-Value="editingApt.Reason" />
                    </div>
                    <div class="col-md-4 mb-3">
                        <label class="form-label">Notes</label>
                        <InputText class="form-control" @bind-Value="editingApt.Notes" />
                    </div>
                </div>
                <button type="submit" class="btn btn-success me-2">Save</button>
                <button type="button" class="btn btn-secondary" @onclick="CancelForm">Cancel</button>
            </EditForm>
        </div>
    </div>
}

<div class="table-responsive">
    <table class="table table-bordered">
        <thead class="table-light">
            <tr>
                <th>Time</th>
                @for (int i = 0; i < 7; i++)
                {
                    var day = weekStart.AddDays(i);
                    <th class="@(day.Date == DateTime.Today ? "table-info" : "")">
                        @day.ToString("ddd M/d")
                    </th>
                }
            </tr>
        </thead>
        <tbody>
            @for (int hour = 8; hour < 18; hour++)
            {
                <tr>
                    <td class="text-nowrap"><strong>@(new TimeOnly(hour, 0).ToString("h:mm tt"))</strong></td>
                    @for (int d = 0; d < 7; d++)
                    {
                        var slotStart = weekStart.AddDays(d).AddHours(hour);
                        var slotEnd = slotStart.AddHours(1);
                        var slotApts = appointments.Where(a => a.StartTime >= slotStart && a.StartTime < slotEnd).ToList();
                        <td class="@(slotApts.Any() ? "" : "table-success")" style="min-width:120px; cursor:pointer"
                            @onclick="() => ClickSlot(slotStart)">
                            @foreach (var apt in slotApts)
                            {
                                <div class="badge bg-@GetColor(apt.Status) text-wrap mb-1 d-block" style="cursor:pointer"
                                    @onclick:stopPropagation="true" @onclick="() => EditAppointment(apt)">
                                    @apt.Patient.Name<br/>@apt.Reason
                                </div>
                            }
                        </td>
                    }
                </tr>
            }
        </tbody>
    </table>
</div>

@code {
    private DateTime weekStart = DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek);
    private List<Appointment> appointments = new();
    private List<Patient> allPatients = new();
    private bool showForm;
    private Appointment editingApt = new();
    private string conflictMessage = "";

    protected override async Task OnInitializedAsync()
    {
        allPatients = await Clinic.GetPatientsAsync();
        await LoadAppointments();
    }

    private async Task LoadAppointments()
    {
        appointments = await Clinic.GetAllAppointmentsAsync(weekStart, weekStart.AddDays(7));
    }

    private void PrevWeek() { weekStart = weekStart.AddDays(-7); _ = LoadAppointments(); }
    private void NextWeek() { weekStart = weekStart.AddDays(7); _ = LoadAppointments(); }
    private void GoToToday() { weekStart = DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek); _ = LoadAppointments(); }

    private void ShowNewForm()
    {
        editingApt = new Appointment
        {
            StartTime = DateTime.Today.AddHours(9),
            EndTime = DateTime.Today.AddHours(9).AddMinutes(30)
        };
        conflictMessage = "";
        showForm = true;
    }

    private void ClickSlot(DateTime slotStart)
    {
        editingApt = new Appointment { StartTime = slotStart, EndTime = slotStart.AddMinutes(30) };
        conflictMessage = "";
        showForm = true;
    }

    private void EditAppointment(Appointment apt)
    {
        editingApt = apt;
        conflictMessage = "";
        showForm = true;
    }

    private async Task SaveAppointment()
    {
        if (Clinic.HasConflict(editingApt.StartTime, editingApt.EndTime, editingApt.Id == 0 ? null : editingApt.Id))
        {
            conflictMessage = "Time slot conflicts with an existing appointment!";
            return;
        }
        await Clinic.SaveAppointmentAsync(editingApt);
        showForm = false;
        conflictMessage = "";
        await LoadAppointments();
    }

    private void CancelForm() { showForm = false; conflictMessage = ""; }

    private string GetColor(AppointmentStatus s) => s switch
    {
        AppointmentStatus.Scheduled => "primary",
        AppointmentStatus.Completed => "success",
        AppointmentStatus.Cancelled => "secondary",
        AppointmentStatus.NoShow => "danger",
        _ => "light"
    };
}

