                        <InputDate Type="InputDateType.DateTimeLocal" class="form-control" @bind-Value="editingApt.StartTime" />
                    </div>
                    <div class="col-md-4 mb-3">
                        <label class="form-label">End Time</label>
                        <InputDate Type="InputDateType.DateTimeLocal" class="form-control" @bind-Value="editingApt.EndTime" />
                    </div>
                </div>
