<div class="table-responsive">
    <table class="table table-bordered">
        <thead class="table-light">
            <tr>
                <th>Time</th>
                @for (int i = 0; i < 7; i++)
                {
                    var day = weekStart.AddDays(i);
                    <th class="@(day.Date == DateTime.Today ? "table-info" : "")">
                        @day.ToString("ddd M/d")
                    </th>
                }
            </tr>
        </thead>
        <tbody>
            @for (int hour = 8; hour < 18; hour++)
            {
                <tr>
                    <td class="text-nowrap"><strong>@(new TimeOnly(hour, 0).ToString("h:mm tt"))</strong></td>
                    @for (int d = 0; d < 7; d++)
                    {
                        var slotStart = weekStart.AddDays(d).AddHours(hour);
                        var slotEnd = slotStart.AddHours(1);
                        var slotApts = appointments.Where(a => a.StartTime >= slotStart && a.StartTime < slotEnd).ToList();
                        <td class="@(slotApts.Any() ? "" : "table-success")" style="min-width:120px; cursor:pointer"
                            @onclick="() => ClickSlot(slotStart)">
                            @foreach (var apt in slotApts)
                            {
                                <div class="badge bg-@GetColor(apt.Status) text-wrap mb-1 d-block" style="cursor:pointer"
                                    @onclick:stopPropagation="true" @onclick="() => EditAppointment(apt)">
                                    @apt.Patient.Name<br/>@apt.Reason
                                </div>
                            }
                        </td>
                    }
                </tr>
            }
        </tbody>
    </table>
</div>

@code {
    private DateTime weekStart = DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek);
    private List<Appointment> appointments = new();
    private List<Patient> allPatients = new();
    private bool showForm;
    private Appointment editingApt = new();
    private string conflictMessage = "";

    protected override async Task OnInitializedAsync()
    {
        allPatients = await Clinic.GetPatientsAsync();
        await LoadAppointments();
    }

    private async Task LoadAppointments()
    {
        appointments = await Clinic.GetAllAppointmentsAsync(weekStart, weekStart.AddDays(7));
    }

    private void PrevWeek() { weekStart = weekStart.AddDays(-7); _ = LoadAppointments(); }
    private void NextWeek() { weekStart = weekStart.AddDays(7); _ = LoadAppointments(); }
    private void GoToToday() { weekStart = DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek); _ = LoadAppointments(); }

    private void ShowNewForm()
    {
        editingApt = new Appointment
        {
            StartTime = DateTime.Today.AddHours(9),
            EndTime = DateTime.Today.AddHours(9).AddMinutes(30)
        };
        conflictMessage = "";
        showForm = true;
    }

    private void ClickSlot(DateTime slotStart)
    {
        editingApt = new Appointment { StartTime = slotStart, EndTime = slotStart.AddMinutes(30) };
        conflictMessage = "";
        showForm = true;
    }

    private void EditAppointment(Appointment apt)
    {
        editingApt = apt;
        conflictMessage = "";
        showForm = true;
    }

    private async Task SaveAppointment()
    {
        if (Clinic.HasConflict(editingApt.StartTime, editingApt.EndTime, editingApt.Id == 0 ? null : editingApt.Id))
        {
            conflictMessage = "Time slot conflicts with an existing appointment!";
            return;
        }
        await Clinic.SaveAppointmentAsync(editingApt);
        showForm = false;
        conflictMessage = "";
        await LoadAppointments();
    }

    private void CancelForm() { showForm = false; conflictMessage = ""; }

    private string GetColor(AppointmentStatus s) => s switch
    {
        AppointmentStatus.Scheduled => "primary",
        AppointmentStatus.Completed => "success",
        AppointmentStatus.Cancelled => "secondary",
        AppointmentStatus.NoShow => "danger",
        _ => "light"
    };
}
