    private void NewInvoice()
    {
        editingInvoice = new Invoice();
        lineItems = new() { new InvoiceLineItem() };
        dueDate = DateTime.Today.AddDays(30);
        showInvoiceForm = true;
    }

    private void AddLineItem() => lineItems.Add(new InvoiceLineItem());

    private async Task SaveInvoice()
    {
        editingInvoice.DueDate = dueDate;
        editingInvoice.TotalAmount = lineItems.Sum(i => i.Quantity * i.UnitPrice);
        editingInvoice.LineItems = lineItems;
        await Clinic.SaveInvoiceAsync(editingInvoice);
        showInvoiceForm = false;
        invoices = await Clinic.GetInvoicesAsync();
    }

    private void ShowPaymentForm(Invoice inv)
    {
        payingInvoice = inv;
        newPayment = new Payment
        {
            InvoiceId = inv.Id,
            Amount = inv.TotalAmount - inv.Payments.Sum(p => p.Amount)
        };
        showPaymentForm = true;
    }

    private async Task ProcessPayment()
    {
        await Clinic.SavePaymentAsync(newPayment);
        showPaymentForm = false;
        invoices = await Clinic.GetInvoicesAsync();
        payments = await Clinic.GetPaymentsAsync();
    }

    private string InvColor(InvoiceStatus s) => s switch
    {
        InvoiceStatus.Paid => "success",
        InvoiceStatus.Pending => "warning",
        InvoiceStatus.PartiallyPaid => "info",
        InvoiceStatus.Overdue => "danger",
        InvoiceStatus.Cancelled => "secondary",
        _ => "light"
    };
}
